        x1_re = LD(&in_re[5*is+k]);
        x1_im = LD(&in_im[5*is+k]);
        x2_re = LD(&in_re[9*is+k]);
        x2_im = LD(&in_im[9*is+k]);
        x3_re = LD(&in_re[13*is+k]);
