          t0r=_mm512_add_pd(x0_re,x4_re); t0i=_mm512_add_pd(x0_im,x4_im);
          t1r=_mm512_sub_pd(x0_re,x4_re); t1i=_mm512_sub_pd(x0_im,x4_im);
