          t2r=_mm512_add_pd(x2_re,x6_re); t2i=_mm512_add_pd(x2_im,x6_im);
          t3r=_mm512_sub_pd(x2_re,x6_re); t3i=_mm512_sub_pd(x2_im,x6_im);
