        _mm512_store_pd(&spill_im[20*8],x4_im);
        _mm512_store_pd(&spill_re[21*8],x5_re);
        _mm512_store_pd(&spill_im[21*8],x5_im);
        _mm512_store_pd(&spill_re[22*8],x6_re);
        _mm512_store_pd(&spill_im[22*8],x6_im);
        _mm512_store_pd(&spill_re[23*8],x7_re);
        _mm512_store_pd(&spill_im[23*8],x7_im);

        /* sub-FFT n2=3 */
        x0_re = LD(&in_re[3*is+k]);
        x0_im = LD(&in_im[3*is+k]);
        x1_re = LD(&in_re[7*is+k]);
        x1_im = LD(&in_im[7*is+k]);
        x2_re = LD(&in_re[11*is+k]);
        x2_im = LD(&in_im[11*is+k]);
        x3_re = LD(&in_re[15*is+k]);
        x3_im = LD(&in_im[15*is+k]);
        x4_re = LD(&in_re[19*is+k]);
        x4_im = LD(&in_im[19*is+k]);
        x5_re = LD(&in_re[23*is+k]);
