    const __m512d tw_W32_5_re = _mm512_set1_pd(W32_5_re);
    const __m512d tw_W32_5_im = _mm512_set1_pd(W32_5_im);
    const __m512d tw_W32_6_re = _mm512_set1_pd(W32_6_re);
