    const __m512d tw_W32_7_im = _mm512_set1_pd(W32_7_im);
    const __m512d tw_W32_9_re = _mm512_set1_pd(W32_9_re);
    const __m512d tw_W32_9_im = _mm512_set1_pd(W32_9_im);
