        x3_re = LD(&in_re[13*is+k]);
        x3_im = LD(&in_im[13*is+k]);
        x4_re = LD(&in_re[17*is+k]);
        x4_im = LD(&in_im[17*is+k]);
        x5_re = LD(&in_re[21*is+k]);
