          t1r=_mm512_sub_pd(x1_re,x5_re); t1i=_mm512_sub_pd(x1_im,x5_im);
          t2r=_mm512_add_pd(x3_re,x7_re); t2i=_mm512_add_pd(x3_im,x7_im);
          t3r=_mm512_sub_pd(x3_re,x7_re); t3i=_mm512_sub_pd(x3_im,x7_im);
